                        </TableCell>
                        <TableCell
                          className="text-right"
                          data-testid={`text-top-user-count-${user.userId}`}
                        >
                          {user.count}
                        </TableCell>
                        <TableCell
                          className="text-right text-muted-foreground whitespace-nowrap"
                          data-testid={`text-top-user-active-${user.userId}`}
