                      className="text-xs text-muted-foreground whitespace-nowrap pt-1"
                      data-testid={`text-activity-time-${activity.id}`}
                    >
                      {formatDateTime(activity.createdAt)}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

