                    if (ra.cardType === "party") return !ra.wing || (ra.wing === "Other" && !ra.customWing?.trim()) || !getPositionValue(ra) || !ra.level;
                    if (ra.cardType === "govt") return !ra.govPositionId || ra.jurisdictionVillageIds.length === 0;
                    return false;
