            <CardContent className="p-4 flex items-center gap-4">
              <div className="w-12 h-12 rounded-xl flex items-center justify-center flex-shrink-0 bg-white/20">
                <Trophy className="h-6 w-6 text-yellow-300" />
              </div>
              <div className="flex-1 min-w-0">
                <h3 className="font-semibold text-white">
                  {language === "hi" ? "लीडरबोर्ड" : language === "pa" ? "ਲੀਡਰਬੋਰਡ" : "Leaderboard"}
                </h3>
                <p className="text-sm text-white/80">
                  {language === "hi" ? "शीर्ष योगदानकर्ताओं की रैंकिंग देखें" : language === "pa" ? "ਚੋਟੀ ਦੇ ਯੋਗਦਾਨੀਆਂ ਦੀ ਰੈਂਕਿੰਗ ਵੇਖੋ" : "See top contributors ranking"}
                </p>
              </div>
              <ChevronRight className="h-5 w-5 text-white/70 flex-shrink-0" />
            </CardContent>
          </Card>
        </Link>

        <h2 className="text-sm font-medium text-slate-500 uppercase tracking-wider mb-3">{t('availableTasks')}</h2>

        <Link href="/task/harr-sirr-te-chatt">
          <Card className="hover-elevate cursor-pointer border-orange-200" data-testid="task-card-hstc">
            <CardContent className="p-4 flex items-center gap-4">
              <div className="w-12 h-12 rounded-xl flex items-center justify-center flex-shrink-0 bg-orange-500">
                <Home className="h-6 w-6 text-white" />
              </div>
              <div className="flex-1 min-w-0">
                <h3 className="font-semibold text-slate-800">
                  {language === "hi" ? "हर सिर ते छत" : language === "pa" ? "ਹਰ ਸਿਰ ਤੇ ਛੱਤ" : "Harr Sirr te Chatt"}
                </h3>
                <p className="text-sm text-slate-500 line-clamp-2">
                  {language === "hi" ? "जरूरतमंद परिवारों के लिए छत की पहल" : language === "pa" ? "ਲੋੜਵੰਦ ਪਰਿਵਾਰਾਂ ਲਈ ਛੱਤ ਪਹਿਲਕਦਮੀ" : "Roof initiative for needy families"}
                </p>
              </div>
              <div className="flex flex-col items-center gap-1 flex-shrink-0">
                <span className="text-xs font-medium text-orange-600">{t('startTask')}</span>
                <ChevronRight className="h-5 w-5 text-slate-400" />
              </div>
            </CardContent>
          </Card>
        </Link>

        {isLoading && (
          <>
            <Skeleton className="h-20 w-full rounded-lg" />
            <Skeleton className="h-20 w-full rounded-lg" />
            <Skeleton className="h-20 w-full rounded-lg" />
          </>
        )}

        {tasks?.map((task) => {
          const IconComponent = iconMap[task.icon || "ClipboardList"] || ClipboardList;
          const count = submissionCounts?.[task.id] || 0;
          const actionLabel = count > 0 ? t('continueTask') : t('startTask');
          return (
            <Link key={task.id} href={getTaskRoute(task)}>
              <Card className="hover-elevate cursor-pointer" data-testid={`task-card-${task.id}`}>
                <CardContent className="p-4 flex items-center gap-4">
                  <div
                    className="w-12 h-12 rounded-xl flex items-center justify-center flex-shrink-0"
                    style={{ backgroundColor: task.color || "#3b82f6" }}
                  >
                    <IconComponent className="h-6 w-6 text-white" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className="font-semibold text-slate-800">{getTaskName(language, task)}</h3>
                    <p className="text-sm text-slate-500 line-clamp-2">{getTaskDesc(language, task)}</p>
                  </div>
                  <div className="flex flex-col items-center gap-1 flex-shrink-0">
                    <span className="text-xs font-medium text-blue-600" data-testid={`task-action-${task.id}`}>{actionLabel}</span>
                    <ChevronRight className="h-5 w-5 text-slate-400" />
                  </div>
                </CardContent>
              </Card>
            </Link>
          );
        })}

        {!isLoading && tasks?.length === 0 && (
          <div className="text-center py-8 text-slate-500">
            <ClipboardList className="h-12 w-12 mx-auto mb-2 text-slate-300" />
            <p>{t('noTasks')}</p>
          </div>
        )}
      </div>
    </div>
  );
}

